var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"갑자기 왜 그러는 거야, 이브? 뭘 그렇게 뒤져?","JPN":"イヴ、いきなりどうした？　何探してるの？","ENG":"What are you doing, Eve? Why are you rummaging through everything like that?","TWN":"突然怎麼了，伊芙？你翻什麼呀？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"찾고 있거든. 퇴소한 언니 오빠들의 물건.","JPN":"保育園を出たお姉さんとお兄さんたちの物。","ENG":"I'm looking for something. Things that were left behind by people who used to live here.","TWN":"我在找離開的哥哥姊姊們留下的東西。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐라고?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤은 단 한 번이라도 퇴소한 언니, 오빠들의 연락을 받은 적 있어?","JPN":"アンはここから出たお姉さん、お兄さんから、一度でも連絡をもらったことがある？","ENG":"Ann, have you ever heard from anyone who left this place?","TWN":"安妮有沒有接到過離開的哥哥姊姊們的聯繫？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"다들 잘 살고 있나 보지. 갑자기 그런 건 왜 물어?","JPN":"みんな幸せに暮らしてるんでしょ？　なんでそんなこと聞くんだよ。","ENG":"I'm sure they're doing well. Why do you ask?","TWN":"大家應該過得很好吧，為什麼突然問這個？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그럼…… 로젠탈을 퇴소한 언니 오빠들 중에서 기억나는 사람은?","JPN":"じゃあ……ローゼンタールから出た人たちの中で、思い出せる人は？","ENG":"Then... do you remember any names of the people who left Rosenthal?","TWN":"那麼……離開羅森泰的哥哥姊姊們中，你還記得誰？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"야! 아무리 그래도 그거야 당연히……!","JPN":"ちょっと！　いくらなんでも、それは……！","ENG":"Hey! Don't be ridiculous! Of course, I–!","TWN":"喂！當然記得囉，有……！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"당연히…….","JPN":"もちろん……","ENG":"Of course, I...","TWN":"當然……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그거 봐, 나도 똑같아.","JPN":"ほらね、私もなの。","ENG":"See? It's the same for me too.","TWN":"你看，我也一樣。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"이 인형 분명 여길 나간…… 사람한테 받은 물건인데 누구인지 기억이 안나.","JPN":"このぬいぐるみは確かにここから出た……人からもらったのに、それが誰なのか思い出せない。","ENG":"I know for certain that someone who left this place gave me this doll... but I can't remember who it was.","TWN":"這娃娃明明是從離開的哥哥姊姊……那給我的，但我不記得是誰了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그럼 네 말은 보육원 아이들이 사라지고 있다는 거야? 아무도 모르게?","JPN":"じゃあ、保育園の子どもたちが、人知れずいなくなってるってこと？","ENG":"Are you saying that people from this orphanage are disappearing? Right under our noses?","TWN":"那你的意思是，育幼院的孩子正在神不知鬼不覺地消失？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"바보야? 그게 말이 된다고 생각해?","JPN":"バカなの？　そんなことあるはずないよ。","ENG":"Are you stupid? That's impossible.","TWN":"你是傻瓜嗎？這麼想沒道理吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"나도 그걸 확인해보고 싶어.","JPN":"私もそれを確認したいの。","ENG":"I want to figure that out too.","TWN":"我也想確認一下。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"어쩌면 그건…… 내가 꾸고 있는 꿈이랑 관련 있을지도 몰라.","JPN":"もしかしたら、それが……私の夢と関係あるかもしれないから。","ENG":"Maybe... this is somehow related to the dream I've been having.","TWN":"說不定……那個跟我做的夢有關。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"꿈이라고? 그 괴물이 나온다던 그 꿈?","JPN":"夢？　あの化け物が出る夢のこと？","ENG":"Your dreams? You mean the ones with those monsters?","TWN":"夢？那個有怪物出現的夢？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"내 능력 말이야…….","JPN":"私の能力はね……","ENG":"My ability...","TWN":"我的能力……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"공간이나, 물건에 감응해서 그것과 관련된 과거나 미래의 단편을 볼 수 있대.","JPN":"空間や物に感化されて、それと関係のある過去や未来の断片を見ることができるらしいの。","ENG":"They explained that when I respond to a space or an object, I can see glimpses into the past or future.","TWN":"據說是可以感應到空間和物品，看到與它相關的過去或者未來的片段。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"마음대로 쓸 수 있는 건 아니고 순간적으로 떠올라서 과거인지, 미래인지는 모르지만.","JPN":"思い通りに使えるわけじゃないし、一瞬だから過去なのか未来なのかはわからないけど。","ENG":"I can't use it whenever I want, nor do I know if the brief visions are of the past or the future.","TWN":"不是可以隨便想用就用，是突然間想起來，而且也不知道是過去還是未來的事。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"어쩌면 꿈에서 봤던 끔찍한 그건…… 로젠탈에서 벌어질 일일지도 몰라.","JPN":"もしかしたら夢で見たアレは……ローゼンタールで起こることなのかもしれない。","ENG":"But those horrible things I saw in my dreams... That may be happening right here in Rosenthal.","TWN":"也許在夢裡看到的可怕的場景……說不定會發生在羅森泰。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"여길 나간 언니 오빠들의 기억을 모아서 그걸 막아보겠다는 거야?","JPN":"ここから出た人たちの記憶を集めて、それを止めるつもりなの？","ENG":"So are you trying to gather the memories of the ones who left this place to stop it?","TWN":"你是想收集離開這裡的哥哥們姊姊的記憶，阻止惡夢發生嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"...Yeah.","TWN":"……對。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤, 나는 지금 이곳이 좋아.","JPN":"アン、私はここが好き。","ENG":"Ann, I like this place.","TWN":"安妮，我喜歡現在這個地方。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"왜냐하면 여긴 앤과 친구들이 다 함께 살 수 있는 공간이니까.","JPN":"ここはアンと友だち、みんなが一緒に暮らせる場所だから。","ENG":"Because it's where you and our friends live together.","TWN":"因為這裡是安妮和大家可以一起生活的空間。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그러니까…… 꿈속에서 봤던 끔찍한 일이 일어나지 않도록, 막고 싶어!","JPN":"だから……夢で見たことが起きないように、食い止めたい！","ENG":"So... I want to stop those terrible things I saw in my dream from happening!","TWN":"所以說……我想阻止在夢裡看到的可怕的事情發生！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤이 좋아하는 가면 카운터처럼!","JPN":"アンの好きな仮面カウンターみたいに！","ENG":"Just like the Masked Counter you like so much, Ann!","TWN":"就像安妮喜歡的蒙面制裁者一樣！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};